const payload = $input.first().json;
const message = payload.messages?.[0];
const contact = payload.contacts?.[0];
if (!message || message.type !== 'text') return [];
const rawPhone = message.from || '';
const phoneNumber = String(rawPhone).replace(/\D/g, '');
const senderName = contact?.profile?.name || 'Cliente';
const text = message.text?.body || '[Multimedia]';

const isReset = text.trim().toLowerCase() === '/reset';
const isResume = text.trim().toLowerCase() === '/resume';
const isVolver = text.trim().toLowerCase() === '/volver';
const wf = $getWorkflowStaticData('global');
if (!wf.resetEpochs) wf.resetEpochs = {};
if (!wf.humanMode) wf.humanMode = {};
if (!wf.humanModeAt) wf.humanModeAt = {};

const TTL_RESET_MS = 30 * 24 * 60 * 60 * 1000;
const TTL_HUMAN_MS = 7 * 24 * 60 * 60 * 1000;
const now = Date.now();
for (const [phone, ts] of Object.entries(wf.resetEpochs)) {
  if (now - ts > TTL_RESET_MS) delete wf.resetEpochs[phone];
}
for (const [phone, ts] of Object.entries(wf.humanModeAt)) {
  if (now - ts > TTL_HUMAN_MS) {
    delete wf.humanMode[phone];
    delete wf.humanModeAt[phone];
  }
}

if (isReset) {
  wf.resetEpochs[phoneNumber] = now;
  delete wf.humanMode[phoneNumber];
  delete wf.humanModeAt[phoneNumber];
  if (wf.inDesignerMode) delete wf.inDesignerMode[phoneNumber];
  if (wf.inDesignerModeAt) delete wf.inDesignerModeAt[phoneNumber];
}
if (isResume) {
  wf.resetEpochs[phoneNumber] = now;
  delete wf.humanMode[phoneNumber];
  delete wf.humanModeAt[phoneNumber];
  if (wf.inDesignerMode) delete wf.inDesignerMode[phoneNumber];
  if (wf.inDesignerModeAt) delete wf.inDesignerModeAt[phoneNumber];
}
if (isVolver) {
  wf.resetEpochs[phoneNumber] = now;
  delete wf.humanMode[phoneNumber];
  delete wf.humanModeAt[phoneNumber];
  if (wf.inDesignerMode) delete wf.inDesignerMode[phoneNumber];
  if (wf.inDesignerModeAt) delete wf.inDesignerModeAt[phoneNumber];
}

const epoch = wf.resetEpochs[phoneNumber] || 0;
const sessionId = epoch ? phoneNumber + '-' + epoch : phoneNumber;
const chatInput = (isReset || isVolver || isResume) ? 'Hola' : text;

return [{ json: { phoneNumber, senderName, chatInput, sessionId, isReset, isResume } }];

const fechaCorta = new Date().toLocaleString('es-MX', {
  timeZone: 'America/Monterrey',
  day: '2-digit', month: 'short', year: 'numeric'
}).replace(/\./g, '');
const fechaTimestamp = new Date().toISOString();
const { phoneNumber, chatInput } = $input.first().json;
return [{
  json: {
    phoneNumber,
    chatInput,
    upsertNuevo: {
      'TelÃ©fono': phoneNumber,
      'Nombre': '',
      'Email': '',
      'Proyecto': '',
      'Presupuesto': '',
      'Estado': 'Nuevo',
      'Ãšltima InteracciÃ³n': fechaCorta,
      'TranscripciÃ³n': '',
      'Timestamp': fechaTimestamp
    }
  }
}];

const staticData = $getWorkflowStaticData('global');
const phoneNumber = $('Extract Message').item.json.phoneNumber;
const userMsg = $('Extract Message').item.json.chatInput;
const isReset = $('Extract Message').item.json.isReset;

// 1. Obtener texto del agente (Recepcionista o DiseÃ±ador)
const rawText = $json.output || $json.text || $json.message || '';

// 2. Flags de routing
let routeDesigner       = false;
let renderRequest       = false;
let descriptionFurniture = null;
let backToRecep         = false;
let humanHandoff        = false;
let leadComplete        = false;
let leadData            = null;
let galeriaCocinas      = false;
let galeriaClosets      = false;
let galeriaBares        = false;
let galeriaPlafones     = false;
let galeriaPuertas      = false;
let galeriaMueblesTV    = false;
let galeriaLavanetas    = false;

// 3. Parseo de tags
if (rawText.includes('[ROUTE_DESIGNER]')) {
  routeDesigner = true;
  if (!staticData.inDesignerMode) staticData.inDesignerMode = {};
  if (!staticData.inDesignerModeAt) staticData.inDesignerModeAt = {};
  staticData.inDesignerMode[phoneNumber] = true;
  staticData.inDesignerModeAt[phoneNumber] = Date.now();
}

const renderMatch = rawText.match(/\[RENDER_REQUEST\]([\s\S]*?)\[\/RENDER_REQUEST\]/);
if (renderMatch) {
  renderRequest = true;
  descriptionFurniture = renderMatch[1].trim();
}

if (rawText.includes('[BACK_TO_RECEPCIONISTA]')) backToRecep = true;
if (rawText.includes('[HUMAN_HANDOFF]')) humanHandoff = true;

const leadMatch = rawText.match(/\[LEAD_COMPLETE\]([\s\S]*?)\[\/LEAD_COMPLETE\]/);
if (leadMatch) {
  leadComplete = true;
  try {
    leadData = JSON.parse(leadMatch[1].trim());
    const renderData = staticData.renderData?.[phoneNumber];
    if (renderData?.generatedImageUrl) {
      leadData.generatedImageUrl = renderData.generatedImageUrl;
    } else {
      leadData.generatedImageUrl = null;
    }
  } catch (e) {
    leadData = { parseError: true, raw: leadMatch[1].trim() };
  }
}

if (rawText.includes('[GALERIA_COCINAS]'))    galeriaCocinas   = true;
if (rawText.includes('[GALERIA_CLOSETS]'))    galeriaClosets   = true;
if (rawText.includes('[GALERIA_BARES]'))      galeriaBares     = true;
if (rawText.includes('[GALERIA_PLAFONES]'))   galeriaPlafones  = true;
if (rawText.includes('[GALERIA_PUERTAS]'))    galeriaPuertas   = true;
if (rawText.includes('[GALERIA_MUEBLES_TV]')) galeriaMueblesTV = true;
if (rawText.includes('[GALERIA_LAVANETAS]'))  galeriaLavanetas = true;

// 4. TTL inDesignerMode 24h
const modeAt = staticData.inDesignerModeAt?.[phoneNumber] || 0;
if ((Date.now() - modeAt) > 86400000 && staticData.inDesignerMode?.[phoneNumber]) {
  staticData.inDesignerMode[phoneNumber] = false;
}

// 5. Limpiar inDesignerMode si el DiseÃ±ador cerrÃ³ o transfiriÃ³
if (leadComplete || humanHandoff || backToRecep) {
  if (staticData.inDesignerMode) staticData.inDesignerMode[phoneNumber] = false;
  if (staticData.inDesignerModeAt) delete staticData.inDesignerModeAt[phoneNumber];
}

// 6. GalerÃ­a: mapa de imÃ¡genes con URLs reales de Cloudinary
const GALERIA_IMAGES = {
  COCINAS:    ['https://res.cloudinary.com/dqxjg4qlb/image/upload/v1778017408/Cocina__gsvwif.jpg', 'https://res.cloudinary.com/dqxjg4qlb/image/upload/v1778017407/Cocina_dbrfwf.jpg'],
  CLOSETS:    ['https://res.cloudinary.com/dqxjg4qlb/image/upload/v1778017405/vestidores_gj5gzs.jpg'],
  PLAFONES:   ['https://res.cloudinary.com/dqxjg4qlb/image/upload/v1778017375/plafon_s20od3.jpg'],
  PUERTAS:    ['https://res.cloudinary.com/dqxjg4qlb/image/upload/v1778017375/puerta_kfsuhg.jpg'],
  MUEBLES_TV: ['https://res.cloudinary.com/dqxjg4qlb/image/upload/v1778017409/muebleTV_szzzva.jpg'],
  BARES:      ['https://res.cloudinary.com/dqxjg4qlb/image/upload/v1778017403/bares_ryjvei.jpg'],
  LAVANETAS:  ['https://res.cloudinary.com/dqxjg4qlb/image/upload/v1778017402/lavanetas_x9swji.jpg']
};

let galeria = null;
let imagenes = [];
if (galeriaCocinas)   { galeria = 'COCINAS';    imagenes = GALERIA_IMAGES.COCINAS; }
if (galeriaClosets)   { galeria = 'CLOSETS';    imagenes = GALERIA_IMAGES.CLOSETS; }
if (galeriaBares)     { galeria = 'BARES';      imagenes = GALERIA_IMAGES.BARES; }
if (galeriaPlafones)  { galeria = 'PLAFONES';   imagenes = GALERIA_IMAGES.PLAFONES; }
if (galeriaPuertas)   { galeria = 'PUERTAS';    imagenes = GALERIA_IMAGES.PUERTAS; }
if (galeriaMueblesTV) { galeria = 'MUEBLES_TV'; imagenes = GALERIA_IMAGES.MUEBLES_TV; }
if (galeriaLavanetas) { galeria = 'LAVANETAS';  imagenes = GALERIA_IMAGES.LAVANETAS; }

// 7. Limpiar tags del texto visible al cliente
const cleanMessage = rawText
  .replace(/\[ROUTE_DESIGNER\]/g, '')
  .replace(/\[RENDER_REQUEST\][\s\S]*?\[\/RENDER_REQUEST\]/g, '')
  .replace(/\[BACK_TO_RECEPCIONISTA\]/g, '')
  .replace(/\[HUMAN_HANDOFF\]/g, '')
  .replace(/\[LEAD_COMPLETE\][\s\S]*?\[\/LEAD_COMPLETE\]/g, '')
  .replace(/\[GALERIA_COCINAS\]/g, '')
  .replace(/\[GALERIA_CLOSETS\]/g, '')
  .replace(/\[GALERIA_BARES\]/g, '')
  .replace(/\[GALERIA_PLAFONES\]/g, '')
  .replace(/\[GALERIA_PUERTAS\]/g, '')
  .replace(/\[GALERIA_MUEBLES_TV\]/g, '')
  .replace(/\[GALERIA_LAVANETAS\]/g, '')
  .trim();

// 8. HistÃ³rico
if (!staticData.history) staticData.history = {};
if (isReset) staticData.history[phoneNumber] = [];
if (!staticData.history[phoneNumber]) staticData.history[phoneNumber] = [];
const cleanUser = (userMsg || '').replace(/\s+/g, ' ').trim();
const cleanBot = (cleanMessage || '').replace(/\s+/g, ' ').trim();
staticData.history[phoneNumber].push('U: ' + cleanUser);
staticData.history[phoneNumber].push('B: ' + cleanBot);
if (staticData.history[phoneNumber].length > 12) staticData.history[phoneNumber] = staticData.history[phoneNumber].slice(-12);
const soloUser = staticData.history[phoneNumber].filter(x => x.startsWith('U: ')).map(x => x.slice(3)).slice(-4);
const transcripcion = soloUser.join(' | ');

const now = new Date();
const fechaCorta = now.toLocaleString('es-MX', { timeZone: 'America/Monterrey', day: '2-digit', month: 'short', year: 'numeric' }).replace(/\./g, '');
const fechaTimestamp = now.toISOString();

const upsertParcial = leadComplete ? null : {
  'TelÃ©fono': phoneNumber,
  'Estado': 'Nuevo',
  'Ãšltima InteracciÃ³n': fechaCorta,
  'TranscripciÃ³n': transcripcion,
};

return [{
  json: {
    phoneNumber,
    cleanMessage,
    leadComplete,
    leadData,
    transcripcion,
    fechaCorta,
    fechaTimestamp,
    upsertParcial,
    humanHandoff,
    backToRecep,
    routeDesigner,
    renderRequest,
    descriptionFurniture,
    galeria,
    imagenes,
    sendShowreel: false,
    senderName: $('Extract Message').item.json.senderName,
    inDesignerMode: staticData.inDesignerMode?.[phoneNumber] === true,
  }
}];

const { phoneNumber, leadData, transcripcion, fechaCorta, fechaTimestamp } = $input.first().json;

return [{
  json: {
    phoneNumber,
    leadData,
    upsertCalificado: {
      'TelÃ©fono': phoneNumber,
      'Nombre': leadData.nombre || leadData.Nombre || '',
      'Email': leadData.email || leadData.Email || '',
      'Proyecto': leadData.tipo ? `[${leadData.tipo}] - ${leadData.descripcion || ''}` : (leadData.proyecto || ''),
      'Presupuesto': leadData.presupuesto || leadData.Presupuesto || 'No proporcionado',
      'Estado': 'Calificado',
      'Ãšltima InteracciÃ³n': fechaCorta,
      'TranscripciÃ³n': transcripcion,
      'Timestamp': fechaTimestamp || new Date().toISOString()
    }
  }
}];

