const lead = $input.first().json;
const phoneNumber = $('Extract Message').item.json.phoneNumber;
const userMessage = $('Extract Message').item.json.chatInput;
const sessionId = $('Extract Message').item.json.sessionId;
const nombre = lead.Nombre || 'cliente';
const proyecto = lead.Proyecto || '';

const proyectoCtx = proyecto ? `\n[CONTEXTO INTERNO: Proyecto ya existe: "${proyecto}". NO ofrezcas diseÃ±o nuevo ni render. Si el cliente pide un diseÃ±o nuevo, responde: "Veo que ya tenemos un proyecto en progreso para usted. Nuestro equipo estÃ¡ trabajando en ello. Â¿Hay algo que quiera ajustar del diseÃ±o actual?"]` : '';

const chatInput = `[CONTEXTO INTERNO: Este cliente (${nombre}) YA ESTÃ REGISTRADO como Calificado. NO le pidas nombre, email ni datos. SalÃºdalo por su nombre, recuÃ©rdale que ya lo tienes registrado y que el equipo de ventas se pondrÃ¡ en contacto. Responde sus preguntas/dudas. Si el cliente pide hablar con ventas o cotizar, NO inicies calificaciÃ³n â€” simplemente confirma que el equipo lo contactarÃ¡. Si insiste en registrarse de nuevo, sugiÃ©rele escribir /reset.]${proyectoCtx}\n\nMensaje del cliente: ${userMessage}`;

return [{ json: { phoneNumber, chatInput, sessionId, isCalificado: true } }];

const phoneNumber = $('Extract Message').item.json.phoneNumber;
const response = $input.first().json;
const rows = response?.values || [];
if (rows.length === 0) {
  return [{ json: { found: false, Estado: '', Nombre: '', phoneNumber } }];
}
const headers = rows[0];
const idIdx = headers.indexOf('TelÃ©fono');
const estadoIdx = headers.indexOf('Estado');
const nombreIdx = headers.indexOf('Nombre');
const proyectoIdx = headers.indexOf('Proyecto');
if (idIdx === -1) {
  return [{ json: { found: false, Estado: '', Nombre: '', Proyecto: '', phoneNumber } }];
}
const norm = (p) => String(p || '').replace(/\D/g, '');
let found = null;
for (let i = 1; i < rows.length; i++) {
  if (norm(rows[i][idIdx]) === norm(phoneNumber)) {
    found = rows[i];
    break;
  }
}
if (!found) {
  return [{ json: { found: false, Estado: '', Nombre: '', Proyecto: '', phoneNumber } }];
}
return [{ json: {
  found: true,
  Estado: found[estadoIdx] || '',
  Nombre: found[nombreIdx] || '',
  Proyecto: found[proyectoIdx] || '',
  phoneNumber
} }];

const { phoneNumber } = $input.first().json;
const wf = $getWorkflowStaticData('global');
if (!wf.humanMode) wf.humanMode = {};
const isPaused = wf.humanMode[phoneNumber] === true;
return [{ json: { ...$input.first().json, isPaused } }];

const { phoneNumber, senderName, cleanMessage, fechaCorta } = $input.first().json;
const wf = $getWorkflowStaticData('global');
if (!wf.humanMode) wf.humanMode = {};
if (!wf.humanModeAt) wf.humanModeAt = {};
wf.humanMode[phoneNumber] = true;
wf.humanModeAt[phoneNumber] = Date.now();

const history = (wf.history && wf.history[phoneNumber]) || [];
const historyText = history.length > 0 ? history.slice(-10).join('\n') : '(sin historial)';
const phoneFormatted = phoneNumber.startsWith('+') ? phoneNumber : '+' + phoneNumber;

const contextMessage = `--- Contexto WhatsApp ---\nNÃºmero: ${phoneNumber}\nNombre: ${senderName || 'Desconocido'}\nFecha: ${fechaCorta}\n\nHistorial:\n${historyText}\n\nâš  El cliente solicitÃ³ hablar con un agente humano.`;

return [{ json: {
  phoneNumber,
  phoneFormatted,
  senderName: senderName || 'Cliente WhatsApp',
  cleanMessage,
  contextMessage,
  fechaCorta
} }];

const rawPhone = $input.first().json.phoneNumber || $input.first().json.body?.phoneNumber || '';
const phoneNumber = String(rawPhone).replace(/\D/g, '');
const wf = $getWorkflowStaticData('global');
if (!wf.resetEpochs) wf.resetEpochs = {};
if (phoneNumber) {
  wf.resetEpochs[phoneNumber] = Date.now();
  if (wf.humanMode) delete wf.humanMode[phoneNumber];
  if (wf.humanModeAt) delete wf.humanModeAt[phoneNumber];
}
return [{ json: { ok: true, phoneNumber } }];

const phone = $('Extract Message').item.json.phoneNumber;
const staticData = $getWorkflowStaticData('global');
const modeAt = staticData.inDesignerModeAt?.[phone] || 0;
const expired = (Date.now() - modeAt) > 86400000;
if (expired && staticData.inDesignerMode?.[phone]) {
  staticData.inDesignerMode[phone] = false;
  delete staticData.inDesignerModeAt[phone];
}
const inDesignerMode = staticData.inDesignerMode?.[phone] === true;
return [{ json: { ...$json, inDesignerMode } }];

const MAX_RENDERS = 3;
const phone = $json.phoneNumber || '';
const desc = ($json.descriptionFurniture || '').toLowerCase();

// Solo bloquear contenido explÃ­citamente prohibido â€” Gemini maneja el resto
const BLOCKED = /pornograf|sex|desnud|arma|droga|coche|carro|vehiculo|mascota/;
const BLOCKED_TERMS = ['pornografÃ­a', 'sex', 'desnudo', 'armas', 'drogas', 'coche', 'carro', 'vehÃ­culo', 'mascota'];

// Leer contador de renders del staticData
const renderData = $getWorkflowStaticData('global').renderData || {};
const clientData = renderData[phone] || { renderCount: 0 };

const isBlocked = BLOCKED.test(desc);
const overLimit = clientData.renderCount >= MAX_RENDERS;

const validRender = !isBlocked && !overLimit;

// Detectar palabra bloqueada especÃ­fica
let blockedWord = null;
if (isBlocked) {
  for (const term of BLOCKED_TERMS) {
    if (desc.includes(term.toLowerCase())) {
      blockedWord = term;
      break;
    }
  }
}

return {
  ...$json,
  validRender,
  renderCount: clientData.renderCount,
  bypassReason: isBlocked ? 'blocked_content' : (overLimit ? 'limit_reached' : null),
  blockedWord: blockedWord,
  shouldLogBlockedWord: isBlocked && blockedWord !== null
};

const prev = $('Validar Tema').item.json;
const values = $input.item.json.embedding?.values || [];
return { ...prev, queryEmbedding: values };

const ctx = $('Extraer Embedding DescripciÃ³n').item.json;
const queryEmbedding = ctx.queryEmbedding;
const phone = ctx.phoneNumber;
const desc = ctx.descriptionFurniture;

const catalogItems = $('Leer Catalogo Render').all()
  .filter(item => item.json.embedding && item.json.cloudinary_url)
  .map(item => {
    let emb;
    try { emb = JSON.parse(item.json.embedding); } catch(e) { return null; }
    return { ...item.json, embeddingParsed: emb };
  })
  .filter(Boolean);

if (catalogItems.length === 0) {
  return [{ json: { ...ctx, top3: [], validRender: false, bypassReason: 'empty_catalog' } }];
}

function cosineSim(a, b) {
  let dot = 0, normA = 0, normB = 0;
  for (let i = 0; i < a.length; i++) {
    dot += a[i] * b[i];
    normA += a[i] * a[i];
    normB += b[i] * b[i];
  }
  return dot / (Math.sqrt(normA) * Math.sqrt(normB));
}

const scored = catalogItems.map(item => ({
  ...item,
  score: cosineSim(queryEmbedding, item.embeddingParsed)
})).sort((a, b) => b.score - a.score);

const top3 = scored.slice(0, 3);

if (top3[0].score < 0.5) {
  return [{ json: { ...ctx, top3: [], validRender: false, bypassReason: 'low_similarity' } }];
}

return [{
  json: {
    ...ctx,
    top3: top3.map(i => ({ id: i.id, cloudinary_url: i.cloudinary_url, score: i.score, categoria: i.categoria })),
    top3Refs: top3.map(i => i.cloudinary_url).join(', ')
  }
}];

const top3 = $json.top3 || [];
const refUrls = top3.map((r, i) => `Referencia ${i+1}: ${r.cloudinary_url}`).join('
');
const prompt = `Genera UNA imagen fotorrealista de un mueble fabricado por Reyna Cocinas y CarpinterÃ­as Finas (Monterrey, MÃ©xico), 37 aÃ±os de oficio. Estilo: carpinterÃ­a fina, calidad alta, ambiente residencial.

Mueble solicitado: "${$json.descriptionFurniture}"

ImÃ¡genes de referencia de estilo (usa estas como guÃ­a de materiales y acabados):
${refUrls}

REGLAS ESTRICTAS:
- Solo muebles fijos a medida (cocinas, closets, bares, plafones, puertas, muebles de TV, lavanetas). 
- Sin personas, sin texto sobreimpreso, sin marcas de agua.
- IluminaciÃ³n cÃ¡lida, fondo neutro.
- ComposiciÃ³n de catÃ¡logo de carpinterÃ­a.`;

return { ...$json, geminiPrompt: prompt };

const prev = $('Preparar Prompt Render').item.json;
const parts = $input.item.json.candidates?.[0]?.content?.parts || [];
const imagePart = parts.find(p => p.inlineData?.mimeType?.startsWith('image/'));

if (!imagePart) {
  return { ...prev, renderFailed: true, base64Image: null };
}

return {
